import{_ as i,o as s,c as t,a2 as a}from"./chunks/framework.DvbpArpZ.js";const k=JSON.parse('{"title":"Tiers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tiers.md","filePath":"guide/tiers.md"}'),r={name:"guide/tiers.md"};function n(o,e,l,h,d,p){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="tiers" tabindex="-1">Tiers <a class="header-anchor" href="#tiers" aria-label="Permalink to &quot;Tiers&quot;">​</a></h1><p>Tierward uses four tiers, each one adding more structure and enforcement. Start at the tier that fits your current risk level and move up when you need more.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Pipeline</th><th>Best for</th></tr></thead><tbody><tr><td><strong>0 — Discovery</strong></td><td>Stop hook only</td><td>First exploration, zero process overhead</td></tr><tr><td><strong>S — Fast Lane</strong></td><td>4 steps, scope-confirm</td><td>Solo dev, low-risk changes, quick fixes</td></tr><tr><td><strong>M — Standard</strong></td><td>13 phases, 3 STOP gates</td><td>Feature blocks, 1–2 collaborators</td></tr><tr><td><strong>L — Full</strong></td><td>14 phases, 4 STOP gates</td><td>Team projects, complex domain changes</td></tr></tbody></table><p>Every tier includes the Stop hook. Process adds on top, not instead.</p><h2 id="tier-0-—-discovery" tabindex="-1">Tier 0 — Discovery <a class="header-anchor" href="#tier-0-—-discovery" aria-label="Permalink to &quot;Tier 0 — Discovery&quot;">​</a></h2><p>The lightest possible setup. You get a Stop hook that mechanically blocks Claude from completing a task until your tests pass. No pipeline, no audit skills, no governance files beyond what&#39;s strictly necessary.</p><p>Use Tier 0 when you&#39;re exploring Tierward for the first time, running a solo spike, or working on a codebase where the cost of process outweighs the benefit.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # select Tier 0 in the wizard</span></span></code></pre></div><h2 id="tier-s-—-fast-lane" tabindex="-1">Tier S — Fast Lane <a class="header-anchor" href="#tier-s-—-fast-lane" aria-label="Permalink to &quot;Tier S — Fast Lane&quot;">​</a></h2><p>For a single developer moving quickly. Adds four pipeline steps and a scope-confirm gate:</p><ol><li>Scope confirm: Claude states what it&#39;s about to do; you approve or redirect</li><li>Implementation</li><li><code>/simplify</code>: early returns, dead code removal, nesting reduction</li><li>Stop hook: tests must pass</li></ol><p>Use Tier S for personal projects, bugfixes, and any work where a lightweight review contract is enough. Most solo projects live here.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tier=s</span></span></code></pre></div><h2 id="tier-m-—-standard" tabindex="-1">Tier M — Standard <a class="header-anchor" href="#tier-m-—-standard" aria-label="Permalink to &quot;Tier M — Standard&quot;">​</a></h2><p>For small teams building features together. Adds 13 development phases with three explicit STOP gates:</p><ul><li><strong>Gate 1</strong>: after requirements, spec reviewed before any code</li><li><strong>Gate 2</strong>: after implementation, code reviewed before tests</li><li><strong>Gate 3</strong>: after testing, QA sign-off before merge</li></ul><p>Also enables the team skills library: <code>/pr-review</code>, <code>/dependency-scan</code>, <code>/migration-audit</code>, <code>/accessibility-audit</code>, <code>/test-audit</code>, and more.</p><p>Use Tier M when you&#39;re working with at least one other person, shipping features to users, or when the cost of a regression is meaningful.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tier=m</span></span></code></pre></div><h2 id="tier-l-—-full" tabindex="-1">Tier L — Full <a class="header-anchor" href="#tier-l-—-full" aria-label="Permalink to &quot;Tier L — Full&quot;">​</a></h2><p>The tier for team projects with complex domain changes. Adds a fourth STOP gate and the context-review pipeline skill (<code>/context-review</code>) that runs after block closure to recompact <code>CLAUDE.md</code> and detect context drift before the next block opens.</p><p>Use Tier L for regulated environments, large feature sets, or any project where a mistake in one block can silently break another.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tier=l</span></span></code></pre></div><h2 id="upgrading" tabindex="-1">Upgrading <a class="header-anchor" href="#upgrading" aria-label="Permalink to &quot;Upgrading&quot;">​</a></h2><p>You can move up a tier at any time:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tier=m</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # promote to Tier M</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # upgrade template files at your current tier</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --anthropic</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # preview diff for Anthropic-influenced files</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --anthropic</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # apply with .bak backup</span></span></code></pre></div><p>Upgrades are non-destructive. Custom files (anything prefixed <code>custom-</code>) are never overwritten.</p><h2 id="which-tier-should-i-use" tabindex="-1">Which tier should I use? <a class="header-anchor" href="#which-tier-should-i-use" aria-label="Permalink to &quot;Which tier should I use?&quot;">​</a></h2><ul><li><strong>You&#39;re trying Tierward for the first time</strong> → Tier 0</li><li><strong>Solo project or bugfix</strong> → Tier S</li><li><strong>Feature work with a collaborator</strong> → Tier M</li><li><strong>Team of 3+, regulated environment, or high-stakes codebase</strong> → Tier L</li></ul><p>When in doubt, start one tier lower. The upgrade path is cheap; the overhead of a tier you don&#39;t need is not.</p>`,31)])])}const g=i(r,[["render",n]]);export{k as __pageData,g as default};
